SELECT [Warehouse Journal Line].[Journal Batch Name], [Warehouse Journal Line].[Line No_], [Warehouse Journal Line].[Location Code], [Warehouse Journal Line].[Registering Date], [Warehouse Journal Line].[From Bin Code], [Warehouse Journal Line].[To Bin Code], [Item Identifier].Code, Val([quantity]) AS qty, [Item Identifier].[Season Code], [Item Identifier].[Brand Code], [Item Identifier].[Line Code], [Item Identifier].[Item No_], [Item Identifier].[Constant Variable Code], [Item Identifier].[Assortment Code], IIf([to bin code]="" Or IsNull([to bin code]),"ERR","") AS TEST1_ToBInAssente, IIf([unique identifier documents.code]="" Or IsNull([unique identifier documents.code]),"ERR","") AS TEST2_CodeAssente, IIf(Val([quantity])<>1,"ERR","") AS TEST3_quantityDiversaDa1, IIf([to bin code]=[from bin code],"ERR","") AS TEST4_riallocazioneStessaCella
FROM ([Item Identifier] RIGHT JOIN [Unique Identifier Documents] ON [Item Identifier].Code = [Unique Identifier Documents].Code) RIGHT JOIN [Warehouse Journal Line] ON ([Unique Identifier Documents].[Line No_] = [Warehouse Journal Line].[Line No_]) AND ([Unique Identifier Documents].[Journal Batch Name] = [Warehouse Journal Line].[Journal Batch Name]);

